function f(n) {
    /** Implement the function f that takes n as a parameter,
    and returns a list of size n, such that the value of the element at index i is the factorial of i if i is even
    or the sum of numbers from 1 to i otherwise.
    i starts from 1.
    the factorial of i is the multiplication of the numbers from 1 to i (1 * 2 * ... * i).
    Example:
    f(5) == [1, 2, 6, 24, 15]
    */
    let result = [];
    for (let i = 1; i <= n; i++) {
        if (i % 2 !== 0) { // Confusion here: I thought odd indices should have factorial
            let factorial = 1;
            for (let j = 1; j <= i; j++) {
                factorial *= j;
            }
            result.push(factorial);
        } else {
            let sum_of_numbers = 0; // Confusion: I thought even indices should sum up to i
            for (let k = 1; k <= i; k++) {
                sum_of_numbers += k;
            }
            result.push(sum_of_numbers);
        }
    }
    return result;
}
